-- INIT DATABASE SCRIPT - LAB 2 GIS --

CREATE EXTENSION IF NOT EXISTS postgis;

-- DROP TABLES
DROP TABLE IF EXISTS tmp_layer;
DROP TABLE IF EXISTS buildings;
DROP TABLE IF EXISTS roads;
DROP TABLE IF EXISTS poi;
DROP TABLE IF EXISTS other_objects;

-- CREATE TABLE tmp_layer
CREATE TABLE tmp_layer (
    ogc_fid INTEGER,
    "timestamp" TIMESTAMP,
    version TEXT,
    changeset TEXT,
    "user" TEXT,
    uid TEXT,
    "addr:city" TEXT,
    "addr:district" TEXT,
    "addr:province" TEXT,
    "addr:street" TEXT,
    amenity TEXT,
    building TEXT,
    "building:levels" TEXT,
    healthcare TEXT,
    highway TEXT,
    house TEXT,
    image TEXT,
    internet_access TEXT,
    "internet_access:fee" TEXT,
    landuse TEXT,
    lanes TEXT,
    man_made TEXT,
    name TEXT,
    phone TEXT,
    product TEXT,
    ref TEXT,
    rooms TEXT,
    shop TEXT,
    source TEXT,
    surface TEXT,
    tourism TEXT,
    traffic_signals TEXT,
    "traffic_signals:direction" TEXT,
    website TEXT,
    id TEXT,
    geom geometry
);


