-- BUILDINGS
CREATE TABLE buildings AS
SELECT *
FROM tmp_layer
WHERE building IS NOT NULL;

ALTER TABLE buildings ADD COLUMN gid SERIAL PRIMARY KEY;

CREATE INDEX idx_buildings_geom ON buildings USING GIST (geom);


-- ROADS
CREATE TABLE roads AS
SELECT *
FROM tmp_layer
WHERE highway IS NOT NULL;

ALTER TABLE roads ADD COLUMN gid SERIAL PRIMARY KEY;

CREATE INDEX idx_roads_geom ON roads USING GIST (geom);


-- POI
CREATE TABLE poi AS
SELECT *
FROM tmp_layer
WHERE amenity IS NOT NULL
   OR shop IS NOT NULL
   OR tourism IS NOT NULL
   OR healthcare IS NOT NULL;

ALTER TABLE poi ADD COLUMN gid SERIAL PRIMARY KEY;

CREATE INDEX idx_poi_geom ON poi USING GIST (geom);


-- OTHER OBJECTS
CREATE TABLE other_objects AS
SELECT *
FROM tmp_layer
WHERE building IS NULL
  AND highway IS NULL
  AND amenity IS NULL
  AND shop IS NULL
  AND tourism IS NULL
  AND healthcare IS NULL;

ALTER TABLE other_objects ADD COLUMN gid SERIAL PRIMARY KEY;

CREATE INDEX idx_other_objects_geom ON other_objects USING GIST (geom);









